"use client";

import { motion, AnimatePresence } from "framer-motion";
import { BookOpen, CalendarDays, CheckSquare, BookMarked, StickyNote } from "lucide-react";

export type TabId = "hoy" | "semana" | "habitos" | "devocional" | "notas";

const NAV_ITEMS: { id: TabId; label: string; icon: React.ReactNode }[] = [
  { id: "hoy",        label: "Hoy",        icon: <BookOpen strokeWidth={2.5} size={18} /> },
  { id: "semana",     label: "Semana",     icon: <CalendarDays strokeWidth={2.5} size={18} /> },
  { id: "habitos",    label: "Hábitos",    icon: <CheckSquare strokeWidth={2.5} size={18} /> },
  { id: "devocional", label: "Devocional", icon: <BookMarked strokeWidth={2.5} size={18} /> },
  { id: "notas",      label: "Notas",      icon: <StickyNote strokeWidth={2.5} size={18} /> },
];

interface LayoutProps {
  activeTab: TabId;
  onTabChange: (tab: TabId) => void;
  children: React.ReactNode;
}

export default function Layout({ activeTab, onTabChange, children }: LayoutProps) {
  return (
    <div className="flex min-h-screen">
      {/* ── SIDEBAR (desktop) ── */}
      <aside className="
        hidden md:flex flex-col
        fixed top-0 left-0 bottom-0 w-[220px]
        glass border-r border-accent-pink/30
        z-50 py-7
      ">
        {/* Logo */}
        <div className="px-6 pb-6 border-b border-accent-pink/30 mb-5">
          <div className="
            w-10 h-10 rounded-xl mb-3
            bg-gradient-to-br from-accent-pink to-deep-rose
            flex items-center justify-center text-xl
            shadow-journal
          ">
            🌸
          </div>
          <h1 className="font-playfair italic text-deep-rose text-[15px] leading-snug">
            Diario de<br />Abigail
          </h1>
        </div>

        {/* Frase motivacional */}
        <p className="px-6 pb-5 text-[10.5px] text-muted-rose italic leading-relaxed border-b border-accent-pink/20 mb-4">
          "Cada día es una página en blanco, llénala con amor."
        </p>

        {/* Nav */}
        <nav className="flex flex-col gap-1">
          {NAV_ITEMS.map((item) => {
            const isActive = activeTab === item.id;
            return (
              <button
                key={item.id}
                onClick={() => onTabChange(item.id)}
                className={`
                  flex items-center gap-3 px-6 py-[10px] mr-3
                  rounded-r-full text-[13px] font-medium
                  transition-all duration-200 text-left
                  ${isActive
                    ? "bg-gradient-to-r from-accent-pink/60 to-accent-pink/10 text-deep-rose font-semibold"
                    : "text-soft hover:bg-accent-pink/20 hover:text-deep-rose"
                  }
                `}
              >
                {/* Dot indicador */}
                <span className={`w-[7px] h-[7px] rounded-full flex-shrink-0 transition-colors ${
                  isActive ? "bg-deep-rose" : "bg-accent-pink"
                }`} />
                {item.label}
              </button>
            );
          })}
        </nav>

        <p className="mt-auto px-6 text-[9.5px] text-muted-rose">✦ v1.0 · Hecho con 💗</p>
      </aside>

      {/* ── MAIN ── */}
      <main className="flex-1 w-full md:ml-[220px] px-5 md:px-10 pt-8 pb-28 md:pb-16 max-w-2xl mx-auto overflow-x-hidden">
        <AnimatePresence mode="wait">
          <motion.div
            key={activeTab}
            initial={{ opacity: 0, y: 14 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
            transition={{ duration: 0.3, ease: "easeOut" }}
          >
            {children}
          </motion.div>
        </AnimatePresence>
      </main>

      {/* ── BOTTOM NAV (móvil) ── */}
      <nav className="
        md:hidden fixed bottom-4 left-1/2 -translate-x-1/2
        flex items-center justify-around gap-1
        glass border border-accent-pink/40
        rounded-full px-4 py-2.5
        shadow-journal-lg
        w-[calc(100%-2rem)] max-w-sm
        z-50
      ">
        {NAV_ITEMS.map((item) => {
          const isActive = activeTab === item.id;
          return (
            <button
              key={item.id}
              onClick={() => onTabChange(item.id)}
              className={`
                flex flex-col items-center gap-1 px-2 py-1.5
                rounded-full flex-1 transition-all duration-200
                ${isActive ? "bg-deep-rose" : ""}
              `}
            >
              <span className={isActive ? "text-white" : "text-muted-rose"}>
                {item.icon}
              </span>
              <span className={`text-[8px] font-medium ${isActive ? "text-white" : "text-muted-rose"}`}>
                {item.label}
              </span>
            </button>
          );
        })}
      </nav>
    </div>
  );
}