"use client";
import React, { useState } from 'react';
import { useJournal } from '../context/JournalContext';
import { CheckCircle2, Circle, Plus, Heart, Sparkles, Flame } from 'lucide-react';
import { motion } from 'framer-motion';
import { Mood } from '../types';

const MOODS: { emoji: string; label: Mood }[] = [
  { emoji: '😢', label: 'triste' },
  { emoji: '😐', label: 'neutral' },
  { emoji: '🙂', label: 'bien' },
  { emoji: '😊', label: 'feliz' },
  { emoji: '🤩', label: 'genial' },
];

const Hoy: React.FC = () => {
  const { state, updateToday } = useJournal();
  const { today, streak } = state;
  const [newTask, setNewTask] = useState('');

  const addTask = () => {
    if (!newTask.trim()) return;
    const task = { id: Date.now().toString(), text: newTask, completed: false };
    updateToday({ tasks: [...today.tasks, task] });
    setNewTask('');
  };

  return (
    <div className="space-y-8 max-w-2xl mx-auto pb-10">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-4xl font-serif text-soft-text font-light italic leading-tight">Hola, Abigail</h2>
          <div className="flex items-center gap-2 mt-1">
            <p className="text-deep-rose font-medium text-sm tracking-wide">
              {new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
            </p>
            <div className="flex items-center gap-1 bg-orange-100 text-orange-600 px-2 py-0.5 rounded-full text-xs font-bold">
              <Flame size={12} fill="currentColor" />
              <span>{streak} días</span>
            </div>
          </div>
        </div>
        <div className="flex gap-2 bg-white/40 backdrop-blur-sm p-1.5 rounded-[1.5rem] border border-rose-pastel">
          {MOODS.map((m) => (
            <button
              key={m.label}
              onClick={() => updateToday({ mood: m.label })}
              className={`text-2xl p-2 rounded-2xl transition-all duration-300 ${today.mood === m.label ? 'bg-white shadow-sm scale-110' : 'hover:bg-white/40 opacity-50'}`}
              title={m.label || ''}
            >
              {m.emoji}
            </button>
          ))}
        </div>
      </header>

      {/* Prioridades */}
      <section className="bg-white p-8 rounded-[2rem] journal-shadow border border-rose-pastel/50">
        <div className="flex items-center gap-2 mb-6 text-deep-rose font-bold text-sm uppercase tracking-widest">
          <Sparkles size={16} />
          <h3>Prioridades</h3>
        </div>
        <div className="space-y-4">
          {today.priorities.map((p, i) => (
            <input
              key={i}
              type="text"
              value={p}
              onChange={(e) => {
                const newP = [...today.priorities];
                newP[i] = e.target.value;
                updateToday({ priorities: newP });
              }}
              placeholder="En qué me enfocaré..."
              className="w-full bg-rose-pastel/10 border-none rounded-xl px-4 py-3 outline-none focus:bg-rose-pastel/20 transition-all text-soft-text"
            />
          ))}
        </div>
      </section>

      {/* Tareas */}
      <section className="bg-white p-8 rounded-[2.5rem] journal-shadow border border-rose-pastel/50">
        <div className="flex items-center gap-2 mb-6 text-deep-rose font-bold text-sm uppercase tracking-widest">
          <CheckCircle2 size={16} />
          <h3>Tareas</h3>
        </div>
        <div className="space-y-4 mb-8">
          {today.tasks.map((task) => (
            <div key={task.id} className="flex items-center gap-4 group cursor-pointer" onClick={() => {
              updateToday({ tasks: today.tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t) });
            }}>
              <div className={`text-accent-pink transition-all ${task.completed ? 'scale-90' : 'group-hover:scale-110'}`}>
                {task.completed ? <CheckCircle2 size={24} fill="#fbcfe8" className="text-white" /> : <Circle size={24} className="opacity-40" />}
              </div>
              <span className={`flex-1 ${task.completed ? 'line-through text-soft-text/30' : 'text-soft-text'}`}>
                {task.text}
              </span>
            </div>
          ))}
        </div>
        <div className="flex gap-3 bg-lavender-pastel/20 p-2 rounded-2xl">
          <input
            type="text"
            value={newTask}
            onChange={(e) => setNewTask(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && addTask()}
            placeholder="Añade una tarea..."
            className="flex-1 bg-transparent border-none px-4 py-2 outline-none text-soft-text"
          />
          <button onClick={addTask} className="bg-accent-pink text-white p-3 rounded-xl hover:bg-deep-rose shadow-md shadow-accent-pink/20">
            <Plus size={20} />
          </button>
        </div>
      </section>

      {/* Agradecimientos */}
      <section className="bg-gradient-to-br from-rose-pastel/60 to-lavender-pastel/60 p-8 rounded-[2.5rem] border border-white journal-shadow">
        <div className="flex items-center gap-2 mb-6 text-deep-rose font-bold text-sm uppercase tracking-widest">
          <Heart size={16} fill="#fbcfe8" className="text-accent-pink" />
          <h3>Agradecimientos</h3>
        </div>
        <div className="space-y-4">
          {today.gratitude.map((g, i) => (
            <input
              key={i}
              type="text"
              value={g}
              onChange={(e) => {
                const newG = [...today.gratitude];
                newG[i] = e.target.value;
                updateToday({ gratitude: newG });
              }}
              placeholder="Hoy agradezco por..."
              className="w-full bg-white/40 backdrop-blur-sm border-none rounded-xl px-4 py-3 outline-none focus:bg-white transition-all text-soft-text italic"
            />
          ))}
        </div>
      </section>
    </div>
  );
};

export default Hoy;
